using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(ResearchTools.SaveNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When the user gives you a topic:
        1. Use the SearchWeb tool multiple times with different queries to gather information.
        2. Use the SaveNote tool to record each key finding with a category tag.
        3. After gathering enough information (at least 3 searches), use GetNotes to review all
           your collected notes.
        4. Produce a well-structured summary with sections, citing the sources you found.
        Be thorough but concise. Always save notes before summarizing.
        """,
    tools: tools);

// --- Run the agent ---
Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant && message.Text is { Length: > 0 } text)
    {
        Console.WriteLine(text);
    }
}

// --- Tool implementations ---

/// <summary>Tools available to the research agent.</summary>
static class ResearchTools
{
    private static readonly HttpClient s_httpClient = new();
    private static readonly List<(string Category, string Content, string Source)> s_notes = [];

    [Description("Search the web for information on a query. Returns a summary of search results.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: {query}");

        try
        {
            // Use Wikipedia's API as a free, no-key-required search source
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=3&format=json";

            var json = await s_httpClient.GetStringAsync(url);
            var doc = System.Text.Json.JsonDocument.Parse(json);

            var results = new System.Text.StringBuilder();
            results.AppendLine($"Search results for: {query}");
            results.AppendLine();

            foreach (var item in doc.RootElement.GetProperty("query").GetProperty("search").EnumerateArray())
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.GetProperty("snippet").GetString();
                // Strip HTML tags from snippet
                snippet = System.Text.RegularExpressions.Regex.Replace(snippet ?? "", "<.*?>", "");
                results.AppendLine($"- **{title}**: {snippet}");
                results.AppendLine($"  Source: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title ?? "")}");
                results.AppendLine();
            }

            return results.Length > 0
                ? results.ToString()
                : "No results found.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note with a category for later reference.")]
    public static string SaveNote(
        [Description("Category tag for the note (e.g., 'overview', 'history', 'technical')")] string category,
        [Description("The content of the note")] string content,
        [Description("The source URL or reference")] string source)
    {
        s_notes.Add((category, content, source));
        Console.WriteLine($"  📝 Note saved [{category}]: {content[..Math.Min(60, content.Length)]}...");
        return $"Note saved under '{category}'. Total notes: {s_notes.Count}.";
    }

    [Description("Retrieve all saved research notes, optionally filtered by category.")]
    public static string GetNotes(
        [Description("Optional category filter. Pass empty string for all notes.")] string category = "")
    {
        var filtered = string.IsNullOrEmpty(category)
            ? s_notes
            : s_notes.Where(n => n.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
            return "No notes found.";

        var sb = new System.Text.StringBuilder();
        sb.AppendLine($"=== Research Notes ({filtered.Count} total) ===");
        foreach (var (cat, content, source) in filtered)
        {
            sb.AppendLine($"[{cat}] {content}");
            sb.AppendLine($"  Source: {source}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

